@using sv_14f8e8f8725840619a8a3ca729d0e4d3.Services

<div class="message-item @(IsThreadStarter ? "message-item--thread-starter" : "")"
     @onmouseenter="() => showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-item__header">
        <span class="message-item__author">@Message.Author</span>
        <span class="message-item__time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-item__content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="message-item__thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-item__actions">
            <button class="message-item__action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <button class="message-item__action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker()
    {
        showEmojiPicker = !showEmojiPicker;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

