@using sv_14f8e8f8725840619a8a3ca729d0e4d3.Services

<div class="channel-sidebar">
    <div class="channel-sidebar__header">
        <h3>Channels</h3>
    </div>
    <div class="channel-sidebar__list">
        @if (Channels is not null)
        {
            @foreach (var channel in Channels)
            {
                <ChannelItem Channel="channel"
                             IsActive="channel.Id == ActiveChannelId"
                             OnSelected="OnChannelSelected" />
            }
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel>? Channels { get; set; }
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@using sv_14f8e8f8725840619a8a3ca729d0e4d3.Services
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer">
    @if (isLoadingMore)
    {
        <div class="message-list__loading">Loading older messages…</div>
    }
    @if (Messages is not null)
    {
        @foreach (var msg in Messages)
        {
            var threadInfo = ThreadSummaries?.FirstOrDefault(t => t.RootMessageId == msg.Id);
            <MessageItem Message="msg"
                         IsThreadStarter="msg.ReplyToId is null && threadInfo is not null"
                         ReplyCount="threadInfo?.ReplyCount ?? 0"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    }
</div>

@code {
    [Parameter] public List<Message>? Messages { get; set; }
    [Parameter] public List<ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMore { get; set; } = true;

    private ElementReference scrollContainer;
    private bool isLoadingMore;
    private DotNetObjectReference<MessageList>? objRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            objRef = DotNetObjectReference.Create(this);
            await JS.InvokeVoidAsync("chatScrollObserver.init", scrollContainer, objRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (isLoadingMore || !HasMore) return;
        isLoadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (objRef is not null)
        {
            try { await JS.InvokeVoidAsync("chatScrollObserver.dispose"); } catch { }
            objRef.Dispose();
        }
    }
}

