{"file_text": "window.chatScrollObserver = {
    _handler: null,
    _el: null,
    init: function (element, dotNetRef) {
        this._el = element;
        this._handler = function () {
            if (element.scrollTop === 0) {
                dotNetRef.invokeMethodAsync('OnScrolledToTop');
            }
        };
        element.addEventListener('scroll', this._handler);
        // Start scrolled to bottom
        element.scrollTop = element.scrollHeight;
    },
    dispose: function () {
        if (this._el && this._handler) {
            this._el.removeEventListener('scroll', this._handler);
            this._handler = null;
            this._el = null;
        }
    }
};
