+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels?.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        activeChannelId = channelId;
+        activeChannel = channels?.FirstOrDefault(c => c.Id == channelId);
+        messages.Clear();
+        hasMore = true;
+        CloseThread();
+
+        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        messages = loaded;
+        hasMore = loaded.Count >= PageSize;
+
+        await ChatService.MarkChannelReadAsync(channelId);
+        BuildThreadSummaries();
+    }
+
+    private async Task LoadMoreMessages()
+    {
+        if (!hasMore || activeChannelId == 0) return;
+        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
+        if (older.Count < PageSize) hasMore = false;
+        messages.InsertRange(0, older);
+        BuildThreadSummaries();
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (activeChannelId == 0) return;
+        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
+        messages.Add(msg);
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        activeThreadRootId = rootMessageId;
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
+        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadReplies = null;
+        activeThreadRootId = 0;
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (activeThreadRootId == 0) return;
+        var reply = await ChatService.SendMessageAsync(activeChannelId, content, activeThreadRootId);
+        threadReplies?.Add(reply);
+        BuildThreadSummaries();
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+        // Refresh messages to show updated reactions
+        var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
+        messages = refreshed;
+
+        if (isThreadOpen && threadReplies is not null)
+        {
+            threadReplies = await ChatService.GetThreadAsync(activeThreadRootId);
+        }
+    }
+
+    private void BuildThreadSummaries()
+    {
+        // Build thread summaries from reply messages in the current message list
+        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
+        threadSummaries = replies
+            .GroupBy(m => m.ReplyToId!.Value)
+            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
+            .ToList();
+    }
+}
